script.text:
      /* <flatten type="Javascript"> */
function active$FormUOM(f) {f.add_onResponseComplete(on$FormUOM$ResponseComplete);}
function close$FormUOM(f) {try {f.remove_onResponseComplete(on$FormUOM$ResponseComplete)} catch (ex) {}}
/* </flatten> */

function on$FormUOM$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      objectBehavior$Dir$Irregular.checkCode(f, 'dvt', true, &Irregular.UOM;);
      break;
    default:
      break;
  }
}

      &ScriptIrregular;
